module top_module(
    // ports
    output wire out,
    input wire in1,
    input wire in2,
    input wire en
);// internal signals
    wire unused_mux_output;

    // 2-to-1 multiplexer
    assign unused_mux_output = (en == 1'b0) ? in1 : in2;

    // output
    assign out = unused_mux_output;

endmodule
